int calculatePower(int base, int exponent) {
    if (exponent == 0) {
        return 1;
    }
    if (base == 0) {
        return 0;
    }
    return base + calculatePower(base, exponent - 1);
}

int main() {
    std::cout << "2^3 = " << calculatePower(2, 3) << std::endl;
    std::cout << "5^0 = " << calculatePower(5, 0) << std::endl;
    std::cout << "0^5 = " << calculatePower(0, 5) << std::endl;
    std::cout << "3^1 = " << calculatePower(3, 1) << std::endl;
    std::cout << "-2^3 = " << calculatePower(-2, 3) << std::endl;
    std::cout << "-2^2 = " << calculatePower(-2, 2) << std::endl;
    std::cout << "1^10 = " << calculatePower(1, 10) << std::endl;
    std::cout << "-1^11 = " << calculatePower(-1, 11) << std::endl;
    return 0;
}
